package skills

import (
    "os"
    "path/filepath"
    "sort"
)

// DiscoveryPaths returns the ordered list of skill search paths (highest precedence first)
func DiscoveryPaths(workDir string) []string {
    home, _ := os.UserHomeDir()
    paths := []string{
        filepath.Join(home, ".pando", "skills"),      // user global (highest)
        filepath.Join(workDir, ".pando", "skills"),     // project local
        filepath.Join(home, ".claude", "skills"),       // Claude compat user
        filepath.Join(workDir, ".claude", "skills"),    // Claude compat project
    }
    return paths
}

// DiscoverSkills scans all paths for SKILL.md files and returns skills ordered by precedence.
// Skills from higher-precedence paths override same-named skills from lower paths.
func DiscoverSkills(paths []string) ([]*Skill, error) {
    seen := make(map[string]*Skill) // name -> skill (first wins = highest precedence)

    for _, basePath := range paths {
        if _, err := os.Stat(basePath); os.IsNotExist(err) {
            continue
        }

        // Walk directory looking for SKILL.md files
        filepath.WalkDir(basePath, func(path string, d os.DirEntry, err error) error {
            if err != nil { return nil } // skip errors
            if d.IsDir() { return nil }
            if d.Name() != "SKILL.md" { return nil }

            skill, err := ParseSkillFile(path)
            if err != nil { return nil } // skip unparseable

            // Only keep highest precedence (first found)
            if _, exists := seen[skill.Metadata.Name]; !exists {
                seen[skill.Metadata.Name] = skill
            }
            return nil
        })
    }

    // Convert to sorted slice
    result := make([]*Skill, 0, len(seen))
    for _, s := range seen {
        result = append(result, s)
    }
    sort.Slice(result, func(i, j int) bool {
        return result[i].Metadata.Name < result[j].Metadata.Name
    })
    return result, nil
}
```

